import assert from 'node:assert';
import {
  HFT_ADVISORY_BUY_CANDIDATE_ID,
  HFT_ADVISORY_SELL_CANDIDATE_ID,
  deriveHftAdvisoryGuard,
  hftCandidateIdForSide,
  hftSideForCandidateId,
  type HftAdvisoryGuardInput,
} from '../hft-advisory-guard';

const BASE_INPUT: HftAdvisoryGuardInput = {
  source: 'test-suite',
  side: 'buy',
  confidence: 0.91,
  obstructionIntensity: 0.05,
  bid: 100.2,
  ask: 100.21,
  lastBid: 100.18,
  tickTimestampMs: 1_000,
  nowMs: 1_010,
  bufferLength: 24,
  inventoryExposure: 150,
  inventoryLimit: 500,
};

const executeBuy = deriveHftAdvisoryGuard(BASE_INPUT);
assert.strictEqual(executeBuy.execute, true);
assert.strictEqual(executeBuy.blockReason, null);
assert.strictEqual(executeBuy.side, 'buy');
assert.strictEqual(executeBuy.candidateId, HFT_ADVISORY_BUY_CANDIDATE_ID);
assert.deepStrictEqual(executeBuy.advisory.decision, {
  kind: 'allocate',
  candidateId: HFT_ADVISORY_BUY_CANDIDATE_ID,
});
assert.strictEqual(executeBuy.aggregate.bufferReady, true);
assert.strictEqual(executeBuy.aggregate.observationAgeMs, 10);
assert.strictEqual(executeBuy.aggregate.loopElapsedMs, 0);

const executeSell = deriveHftAdvisoryGuard({
  ...BASE_INPUT,
  side: 'sell',
});
assert.strictEqual(executeSell.execute, true);
assert.strictEqual(executeSell.candidateId, HFT_ADVISORY_SELL_CANDIDATE_ID);
assert.deepStrictEqual(executeSell.advisory.decision, {
  kind: 'allocate',
  candidateId: HFT_ADVISORY_SELL_CANDIDATE_ID,
});

const staleObservation = deriveHftAdvisoryGuard({
  ...BASE_INPUT,
  nowMs: 1_400,
  maxObservationAgeMs: 250,
  deadlineMs: 500,
});
assert.strictEqual(staleObservation.execute, false);
assert.strictEqual(staleObservation.blockReason, 'stale-observation');

const deadlineExceeded = deriveHftAdvisoryGuard({
  ...BASE_INPUT,
  nowMs: 1_010,
  loopElapsedMs: 30,
  deadlineMs: 25,
  maxObservationAgeMs: 250,
});
assert.strictEqual(deadlineExceeded.execute, false);
assert.strictEqual(deadlineExceeded.blockReason, 'deadline-exceeded');

const adverseSelection = deriveHftAdvisoryGuard({
  ...BASE_INPUT,
  lastBid: 99.8,
  bid: 100.2,
  displayedDepth: 0,
  priceMoveThreshold: 0.05,
});
assert.strictEqual(adverseSelection.execute, false);
assert.strictEqual(adverseSelection.blockReason, 'adverse-selection');

const riskLimited = deriveHftAdvisoryGuard({
  ...BASE_INPUT,
  inventoryExposure: 750,
  inventoryLimit: 500,
});
assert.strictEqual(riskLimited.execute, false);
assert.strictEqual(riskLimited.blockReason, 'risk-limit-reached');

const notReady = deriveHftAdvisoryGuard({
  ...BASE_INPUT,
  bufferLength: 3,
  nowMs: 1_010,
  tickTimestampMs: 1_000,
});
assert.strictEqual(notReady.execute, false);
assert.strictEqual(notReady.blockReason, 'not-ready');

assert.strictEqual(hftCandidateIdForSide('buy'), HFT_ADVISORY_BUY_CANDIDATE_ID);
assert.strictEqual(hftCandidateIdForSide('sell'), HFT_ADVISORY_SELL_CANDIDATE_ID);
assert.strictEqual(hftSideForCandidateId(HFT_ADVISORY_BUY_CANDIDATE_ID), 'buy');
assert.strictEqual(hftSideForCandidateId(HFT_ADVISORY_SELL_CANDIDATE_ID), 'sell');
assert.strictEqual(hftSideForCandidateId(99), null);

console.log('hft-advisory-guard: all tests passed');
